  "type": "CAROUSEL",
  "lessonText": "Explore key symptoms of cold sensations and effective fever management strategies.",
  "data": {
    "slides": [
      {
        "title": "Cold Sensations Overview",
        "content": "Understanding cold sensations is crucial for effective management.\n- Common in viral infections.\n- Can indicate body temperature regulation issues.",
        "imagePrompt": "Illustration of a thermometer and cold symptoms",
        "imageUrl": "https://example.com/cold_overview.jpg"
      },
      {
        "title": "Identifying Symptoms",
        "content": "Recognizing symptoms helps in proper treatment.\n- Chills and shivering.\n- Cold extremities.\n- Fatigue and malaise.",
        "imagePrompt": "Diagram showing symptoms of cold sensations",
        "imageUrl": "https://example.com/symptoms_identification.jpg"
      },
      {
        "title": "Fever Management Techniques",
        "content": "Effective strategies for managing fever include:\n- Hydration to prevent dehydration.\n- Rest to aid recovery.\n- Over-the-counter medications for symptom relief.",
        "imagePrompt": "Image of fever management methods",
        "imageUrl": "https://example.com/fever_management.jpg"
      },
      {
        "title": "When to Seek Help",
        "content": "Know when to consult a healthcare professional:\n- Persistent high fever.\n- Severe symptoms.\n- Symptoms lasting more than a few days.",
        "imagePrompt": "Graphic showing when to seek medical help",
        "imageUrl": "https://example.com/seek_help.jpg"
      }
    ]
  }
}
